import Vue from 'vue';
import axios from 'axios';
import VueAxios from 'vue-axios';
import VueRouter from 'vue-router';
import store from './store';
import VueMoment from 'vue-moment';
import Vuelidate from 'vuelidate';
import vuelidateErrorExtractor, { templates } from 'vuelidate-error-extractor';
import CustomErrorWrapper from '@/views/shared/CustomErrorWrapper.vue';
import Loading from 'vue-loading-overlay';
import { BootstrapVue, IconsPlugin } from 'bootstrap-vue';
import Multiselect from 'vue-multiselect';
import NavLink from '@/views/shared/NavLink.vue';

import App from './App.vue';
import router from './router';

Vue.config.productionTip = false;

Vue.use(VueRouter);
Vue.use(VueAxios, axios);
Vue.use(VueMoment);
Vue.use(Vuelidate);
Vue.use(vuelidateErrorExtractor, {
  template: CustomErrorWrapper,
  messages: {
    required: 'Field is required',
    email: 'Must be a valid email address',
    maxLength: 'Too long',
    minLength: 'Too short'
  }
});
Vue.use(Loading, {
  color: '#0b4d73',
  loader: 'dots',
  width: 64,
  height: 64,
  backgroundColor: '#ffffff',
  blur: '20px',
  transition: 'fade'
});
Vue.use(BootstrapVue);
Vue.use(IconsPlugin);
Vue.component('multiselect', Multiselect);
Vue.component('nav-link', NavLink);

new Vue({
  router,
  store,
  async beforeCreate() {
    await this.$store.dispatch('fetchUser');
    if (!(await this.$store.dispatch('shouldThisLinkWork'))) {
      this.$store.dispatch('redirectIfUrlIsDisabled');
    }
    this.$mount('#app');
  },
  render: h => h(App)
});
