<template>
  <div :class="hasErrors ? 'is-invalid' : ''">
    <slot />
    <div class="invalid-feedback" v-if="hasErrors">
      <div class="error" v-for="error in activeErrorMessages" :key="error">{{ error }}</div>
    </div>
  </div>
</template>

<script>
import { singleErrorExtractorMixin } from 'vuelidate-error-extractor';

export default {
  mixins: [singleErrorExtractorMixin]
};
</script>
