import axios from 'axios';
import Vue from 'vue';
import Vuex from 'vuex';
import router from '../router';
import Loading from 'vue-loading-overlay';

Vue.use(Loading, {
  color: '#0b4d73',
  loader: 'dots',
  width: 64,
  height: 64,
  backgroundColor: '#ffffff',
  blur: '20px',
  transition: 'fade'
});

Vue.use(Vuex);

let plugins = new Vue();

const state = {
  notifications: [],
  user: null
};

const getters = {
  currentUser: state => state.user,
  currentNotifications: state => state.notifications
};

const actions = {
  async notify({ commit, state, dispatch }, payload) {
    state.notifications = [payload.notification].concat(state.notifications);
    setTimeout(() => {
      dispatch('dismissNotification', {
        notification: payload.notification
      });
    }, 5000);
    commit('setNotifications', state.notifications);
  },
  async dismissNotification({ commit, state }, payload) {
    let index = state.notifications.indexOf(payload.notification);
    if (index > -1) {
      state.notifications.splice(index, 1);
      commit('setNotifications', state.notifications);
    }
  },
  async fetchUser({ commit }) {
    return await new Promise((resolve, reject) => {
      axios
        .get('/api/user/get-current-user')
        .then(response => {
          commit('setUser', response.data);
          resolve(response.data);
        })
        .catch(error => reject(error));
    });
  },
  async shouldThisLinkWork({ commit }, url) {
    if (!state.user) {
      await actions.fetchUser();
    }

    let pathname = url ? url.split(/\?(.+)/)[0] : window.location.pathname;

    if (state.user.type == 'tutor') {
      if (!state.user.tutor.basicDataComplete) {
        return pathname == `/tutor/profile/basic-data`;
      }
      if (!state.user.tutor.hasSubjects) {
        return pathname == '/tutor/profile/subjects' || pathname == '/tutor/profile/basic-data';
      }
    }

    if (state.user.type == 'student') {
      if (state.user.student.basicDataComplete == false) {
        return pathname == `/student/profile/basic-data`;
      }
      if (!state.user.student.hasSubjects) {
        return pathname == '/student/profile/subjects' || pathname == '/student/profile/basic-data';
      }
    }

    return true;
  },
  async redirectIfUrlIsDisabled({ commit, dispatch }, url) {
    if (!state.user) {
      await actions.fetchUser();
    }

    let pathname = url ? url.split(/\?(.+)/)[0] : window.location.pathname;
    let query = url ? url.split(/\?(.+)/)[1] : location.search;
    let fullLink = query ? `${pathname}?${query}` : pathname;

    if (state.user.type == 'tutor') {
      if (!state.user.tutor.basicDataComplete) {
        if (pathname != `/student/profile/basic-data`) {
          dispatch('notify', {
            notification: {
              type: 'warning',
              title: 'Warning',
              message: `You have to complete your profile before using mydrasa's other features.`
            }
          });
          router.push(`/tutor/profile/basic-data?returnUrl=${encodeURIComponent(pathname)}`);
        } else {
          router.push(fullLink);
        }
        return;
      }

      if (!state.user.tutor.hasSubjects && pathname != '/tutor/profile/subjects' && pathname != '/tutor/profile/basic-data') {
        dispatch('notify', {
          notification: {
            type: 'warning',
            title: 'Warning',
            message: `You have to add your subjects before using mydrasa's other features.`
          }
        });
        router.push(`/tutor/profile/subjects?returnUrl=${encodeURIComponent(pathname)}`);
        return;
      }
    }

    if (state.user.type == 'student') {
      if (!state.user.student.basicDataComplete) {
        if (pathname != `/student/profile/basic-data`) {
          dispatch('notify', {
            notification: {
              type: 'warning',
              title: 'Warning',
              message: `You have to complete your profile before using mydrasa's other features.`
            }
          });
          router.push(`/student/profile/basic-data?returnUrl=${encodeURIComponent(pathname)}`);
        } else {
          router.push(fullLink);
        }
        return;
      }

      if (!state.user.student.hasSubjects && pathname != '/student/profile/subjects' && pathname != '/student/profile/basic-data') {
        dispatch('notify', {
          notification: {
            type: 'warning',
            title: 'Warning',
            message: `You have to add your subjects before using mydrasa's other features.`
          }
        });
        router.push(`/student/profile/subjects?returnUrl=${encodeURIComponent(pathname)}`);
        return;
      }
    }

    router.push(fullLink);
  },
  async httpPost({ commit, dispatch }, payload) {
    return await new Promise((resolve, reject) => {
      let loader = plugins.$loading;
      if (payload.loader) {
        loader = loader.show();
      }
      plugins.$http
        .post(payload.url, payload.data, { headers: payload.headers })
        .then(response => {
          if (!response.data.succeded) {
            response.data.errors.forEach(error => {
              dispatch('notify', {
                notification: {
                  type: 'danger',
                  title: 'Error',
                  message: error
                }
              });
            });
            if (payload.loader) {
              loader.hide();
            }
            if (response.data.warnings) {
              response.data.warnings.forEach(error => {
                dispatch('notify', {
                  notification: {
                    type: 'danger',
                    title: 'Error',
                    message: error
                  }
                });
              });
            }
            reject();
          } else {
            if (payload.successMessage) {
              dispatch('notify', {
                notification: { type: 'success', title: 'Success', message: payload.successMessage }
              });
            }
            if (payload.loader) {
              loader.hide();
            }
            if (response.data.warnings) {
              response.data.warnings.forEach(error => {
                dispatch('notify', {
                  notification: {
                    type: 'warning',
                    title: 'Warning',
                    message: error
                  }
                });
              });
            }
            resolve(response);
          }
        })
        .catch(error => {
          dispatch('notify', {
            notification: {
              type: 'danger',
              title: 'Error',
              message: 'Something went wrong!'
            }
          });
          console.log(error);
          if (payload.loader) {
            loader.hide();
          }
          reject();
        });
    });
  },
  async httpGet({ commit, dispatch }, payload) {
    return await new Promise((resolve, reject) => {
      let loader = plugins.$loading;
      if (payload.loader) {
        loader = loader.show();
      }
      plugins.$http
        .get(payload.url)
        .then(response => {
          if (!response.data.succeded) {
            response.data.errors.forEach(error => {
              dispatch('notify', {
                notification: {
                  type: 'danger',
                  title: 'Error',
                  message: error
                }
              });
            });
            if (payload.loader) {
              loader.hide();
            }
            if (response.data.warnings) {
              response.data.warnings.forEach(error => {
                dispatch('notify', {
                  notification: {
                    type: 'warning',
                    title: 'Warning',
                    message: error
                  }
                });
              });
            }
            reject();
          } else {
            if (payload.successMessage) {
              dispatch('notify', {
                notification: { type: 'success', title: 'Success', message: payload.successMessage }
              });
            }
            if (payload.loader) {
              loader.hide();
            }
            resolve(response);
          }
        })
        .catch(error => {
          dispatch('notify', {
            notification: {
              type: 'danger',
              title: 'Error',
              message: `Something went wrong!`
            }
          });
          console.log(error);
          if (payload.loader) {
            loader.hide();
          }
          reject();
        });
    });
  },
  async httpGetMultiple({ commit, dispatch }, payload) {
    return await new Promise((resolve, reject) => {
      let loader = plugins.$loading;
      if (payload.loader) {
        loader = loader.show();
      }

      let calls = new Array();
      payload.urls.forEach(url => {
        calls.push(plugins.$http.get(url));
      });

      Promise.all(calls)
        .then(responses => {
          let allOkay = true;
          responses.forEach(response => {
            if (!response.data.succeded) {
              allOkay = false;
              response.data.errors.forEach(error => {
                dispatch('notify', {
                  notification: {
                    type: 'danger',
                    title: 'Error',
                    message: error
                  }
                });
              });
            }
            if (response.data.warnings) {
              response.data.warnings.forEach(error => {
                dispatch('notify', {
                  notification: {
                    type: 'warning',
                    title: 'Warning',
                    message: error
                  }
                });
              });
            }
          });
          if (allOkay) {
            if (payload.successMessage) {
              dispatch('notify', {
                notification: {
                  type: 'success',
                  title: 'Success',
                  message: payload.successMessage
                }
              });
            }
            resolve(responses);
          }
          if (payload.loader) {
            loader.hide();
          }
          if (!allOkay) {
            reject();
          }
        })
        .catch(error => {
          dispatch('notify', {
            notification: {
              type: 'danger',
              title: 'Error',
              message: `Something went wrong!`
            }
          });
          console.log(error);
          if (payload.loader) {
            loader.hide();
          }
          reject();
        });
    });
  }
};

const mutations = {
  setNotifications: function(state, notifications) {
    state.notifications = notifications;
  },
  setUser: function(state, user) {
    Vue.set(state, 'user', user);
  }
};
export default new Vuex.Store({
  state,
  getters,
  actions,
  mutations
});
