<script>
import { mapGetters, mapActions } from 'vuex';

export default {
  async mounted() {},
  watch: {
    '$route': function(to, from) {
      if (this.$route.query.error) {
        this.notify({
          notification: { type: 'danger', title: 'Error', message: this.$route.query.error }
        });
      }
    }
  },
  computed: {
    ...mapGetters(['currentUser', 'currentNotifications']),
    getCurrentYear() {
      return new Date().getFullYear();
    }
  },
  methods: {
    ...mapActions(['fetchUser', 'shouldThisLinkWork', 'redirectIfUrlIsDisabled', 'httpGet', 'notify', 'dismissNotification']),
    logout() {
      this.httpGet({
        url: '/api/user/logout/',
        loader: true
      }).then(() => {
        window.location.href = '/';
      });
    },
    dismiss(notification) {
      this.dismissNotification({ notification: notification });
    }
  }
};
</script>
