import VueRouter from 'vue-router';

const TutorDashboard = () => import(/* webpackChunkName: "tutor" */ '@/views/tutor/Dashboard/Index').then(m => m.default);
const TutorProfileBasicData = () => import(/* webpackChunkName: "tutor" */ '@/views/tutor/profile/BasicData').then(m => m.default);
const TutorProfileSubjects = () => import(/* webpackChunkName: "tutor" */ '@/views/tutor/profile/Subjects').then(m => m.default);
const TutorProfilePrivateTutoring = () => import(/* webpackChunkName: "tutor" */ '@/views/tutor/profile/PrivateTutoring').then(m => m.default);
const TutorProfileChangePassword = () => import(/* webpackChunkName: "tutor" */ '@/views/tutor/profile/ChangePassword').then(m => m.default);
const TutorSubjectsListing = () => import(/* webpackChunkName: "tutor" */ '@/views/tutor/subjects/Index').then(m => m.default);
const TutorSubjectsSubject = () => import(/* webpackChunkName: "tutor" */ '@/views/tutor/subjects/Subject').then(m => m.default);
const TutorSubjectsLessons = () => import(/* webpackChunkName: "tutor" */ '@/views/tutor/subjects/Lessons').then(m => m.default);
const TutorSubjectsLesson = () => import(/* webpackChunkName: "tutor" */ '@/views/tutor/subjects/Lesson').then(m => m.default);
const TutorSubjectsQuiz = () => import(/* webpackChunkName: "tutor" */ '@/views/tutor/subjects/Quiz').then(m => m.default);
const TutorSessions = () => import(/* webpackChunkName: "tutor" */ '@/views/tutor/Sessions/Index').then(m => m.default);
const TutorSession = () => import(/* webpackChunkName: "tutor" */ '@/views/tutor/Sessions/Session').then(m => m.default);
const TutorRecordedSession = () => import(/* webpackChunkName: "tutor" */ '@/views/tutor/Sessions/RecordedSession').then(m => m.default);
const TutorResources = () => import(/* webpackChunkName: "tutor" */ '@/views/tutor/Resources/Index').then(m => m.default);

const StudentDashboard = () => import(/* webpackChunkName: "student" */ '@/views/student/Dashboard/Index').then(m => m.default);
const StudentProfileBasicdata = () => import(/* webpackChunkName: "student" */ '@/views/student/profile/BasicData').then(m => m.default);
const StudentProfileSubjects = () => import(/* webpackChunkName: "student" */ '@/views/student/profile/Subjects').then(m => m.default);
const StudentProfileChangePassword = () => import(/* webpackChunkName: "student" */ '@/views/student/profile/ChangePassword').then(
  m => m.default
);
const BookSession = () => import(/* webpackChunkName: "student" */ '@/views/student/bookSession/Index').then(m => m.default);
const StudentSessions = () => import(/* webpackChunkName: "student" */ '@/views/student/Sessions/Index').then(m => m.default);
const StudentSession = () => import(/* webpackChunkName: "student" */ '@/views/student/Sessions/Session').then(m => m.default);
const StudentRecordedSession = () => import(/* webpackChunkName: "student" */ '@/views/student/Sessions/RecordedSession').then(m => m.default);
const ParentDashboard = () => import(/* webpackChunkName: "parent" */ '@/views/parent/Dashboard/Index').then(m => m.default);

const routes = [
  { name: 'tutor-dashboard', path: '/tutor/dashboard', component: TutorDashboard },
  { name: 'tutor-profile-redirect', path: '/tutor/profile', redirect: '/tutor/profile/basic-data' },
  { name: 'tutor-profile-basic-data', path: '/tutor/profile/basic-data', component: TutorProfileBasicData },
  { name: 'tutor-profile-subjects', path: '/tutor/profile/subjects', component: TutorProfileSubjects },
  { name: 'tutor-profile-private-tutoring', path: '/tutor/profile/private-tutoring', component: TutorProfilePrivateTutoring },
  { name: 'tutor-profile-change-password', path: '/tutor/profile/change-password', component: TutorProfileChangePassword },
  { name: 'tutor-sessions', path: '/tutor/sessions', component: TutorSessions },
  { name: 'tutor-session', path: '/tutor/sessions/:sessionId', component: TutorSession },
  { name: 'tutor-recorded-session', path: '/tutor/sessions/recorded/:sessionId', component: TutorRecordedSession },
  { name: 'tutor-resources', path: '/tutor/resources', component: TutorResources },
  { name: 'tutor-subjects-subjects', path: '/tutor/subjects', component: TutorSubjectsListing },
  { name: 'tutor-subjects-subject', path: '/tutor/subjects/:subjectId', component: TutorSubjectsSubject },
  { name: 'tutor-subjects-lessons', path: '/tutor/subjects/:subjectId/lessons', component: TutorSubjectsLessons },
  {
    name: 'tutor-subjects-lesson',
    path: '/tutor/subjects/:subjectId/lessons/:learningObjectiveId',
    component: TutorSubjectsLesson
  },
  {
    name: 'tutor-subjects-new-quiz',
    path: '/tutor/subjects/:subjectId/lessons/:learningObjectiveId/update-quiz-module',
    component: TutorSubjectsQuiz
  },
  {
    name: 'tutor-subjects-edit-quiz',
    path: '/tutor/subjects/:subjectId/lessons/:learningObjectiveId/update-quiz-module/:moduleId',
    component: TutorSubjectsQuiz
  },
  { name: 'student-dashboard', path: '/student/dashboard', component: StudentDashboard },
  { name: 'student-profile-redirect', path: '/student/profile', redirect: '/student/profile/basic-data' },
  { name: 'student-profile-basic-data', path: '/student/profile/basic-data', component: StudentProfileBasicdata },
  { name: 'student-profile-subjects', path: '/student/profile/subjects', component: StudentProfileSubjects },
  { name: 'student-profile-change-password', path: '/student/profile/change-password', component: StudentProfileChangePassword },
  { name: 'student-sessions', path: '/student/sessions', component: StudentSessions },
  { name: 'student-session', path: '/student/sessions/:sessionId', component: StudentSession },
  { name: 'student-recorded-session', path: '/student/sessions/recorded/:sessionId', component: StudentRecordedSession },
  { name: 'student-book-session', path: '/student/book-a-session', component: BookSession },
  { name: 'parent-dashboard-redirect', path: '/parent', redirect: '/parent/dashboard' },
  { name: 'parent-dashboard', path: '/parent/dashboard', component: ParentDashboard }
];

const router = new VueRouter({
  mode: 'history',
  base: '/',
  linkActiveClass: 'active',
  linkExactActiveClass: 'active',
  routes
});

export default router;
