<template>
  <a @click="click()" href="javascript:;" :class="allClasses">
    <slot />
  </a>
</template>

<script>
import { mapActions, mapGetters } from 'vuex';

export default {
  name: 'nav-link',
  props: ['href', 'cssClass'],
  data() {
    return {
      allClasses: ''
    };
  },
  created() {
    this.updateAllClasses();
    this.$store.watch(
      state => {
        return this.$store.getters.currentUser;
      },
      (newValue, oldValue) => {
        this.updateAllClasses();
      }
    );
  },
  methods: {
    ...mapActions(['shouldThisLinkWork', 'redirectIfUrlIsDisabled', 'notify']),
    async click() {
      if (window.onbeforeunload) {
        if (!confirm(window.onbeforeunload())) {
          return;
        } else {
          window.onbeforeunload = null;
        }
      }
      let message = await this.redirectIfUrlIsDisabled(this.href);
      if (message) {
        this.notify({
          notification: {
            type: 'warning',
            title: 'Warning',
            message: message
          }
        });
      }
    },
    async updateAllClasses() {
      this.allClasses = `${(await this.shouldThisLinkWork(this.href)) ? '' : 'disabled'} ${this.cssClass ? this.cssClass : ''}`;
    }
  },
  computed: mapGetters(['currentUser'])
};
</script>
